select count(1)
from biz_recharge_order
where user_id = #{userId}

select count(1)
from biz_recharge_order
where user_id = #{userId}
  and status = #{status}


select r.*, u.real_name as user_name, au.real_name as audit_user_name,
       fu.real_name as first_audit_user_name, su.real_name as second_audit_user_name
from biz_recharge_order r
left join sys_user u on u.id = r.user_id
left join sys_user au on au.id = r.audit_user_id
left join sys_user fu on fu.id = r.first_audit_user_id
left join sys_user su on su.id = r.second_audit_user_id
where 1 = 1

  and (r.recharge_no like concat('%', #{keyword}, '%')
  or u.real_name like concat('%', #{keyword}, '%')
  or r.remark like concat('%', #{keyword}, '%'))


  and r.status = #{status}


  and r.user_id = #{userId}


  and r.audit_user_id = #{auditUserId}


  and r.amount >= #{minAmount}


  and r.amount <= #{maxAmount}


  and r.create_time >= #{startTime}


  and r.create_time <= #{endTime}


  and u.department_id = #{scopeDepartmentId}

order by r.create_time desc
limit #{offset}, #{pageSize}


